<main class="container-fluid px-3 px-lg-4 py-4"><?php if($this->session->flashdata('success')): ?><div class="alert alert-success border-0 shadow-sm"><?= $this->session->flashdata('success'); ?></div><?php endif; ?><?php if($this->session->flashdata('error')): ?><div class="alert alert-danger border-0 shadow-sm"><?= $this->session->flashdata('error'); ?></div><?php endif; ?><div class="row g-4"><div class="col-lg-4"><div class="panel-card p-3 p-lg-4"><h5 class="fw-bold mb-3">Tambah Maintenance</h5><form action="<?= base_url('index.php/admin/maintenance/simpan') ?>" method="post" class="vstack gap-3"><div><label class="form-label small fw-semibold text-muted">Aset</label><select name="id_aset" class="form-select" required><option value="">Pilih aset</option><?php foreach($aset as $a): ?><option value="<?= $a->id_aset ?>"><?= html_escape($a->nama_aset.' - '.$a->kode_aset) ?></option><?php endforeach; ?></select></div><div><label class="form-label small fw-semibold text-muted">Tanggal Maintenance</label><input type="date" name="tanggal_maintenance" class="form-control" value="<?= date('Y-m-d') ?>" required></div><div><label class="form-label small fw-semibold text-muted">Kondisi Setelah</label><select name="kondisi_setelah" class="form-select"><option>Baik</option><option>Rusak</option><option>Perlu Perbaikan</option><option>Sudah Diperbaiki</option></select></div><div><label class="form-label small fw-semibold text-muted">Deskripsi</label><textarea name="deskripsi" class="form-control" rows="3" required></textarea></div><div><label class="form-label small fw-semibold text-muted">Catatan</label><textarea name="catatan" class="form-control" rows="2"></textarea></div><button class="btn btn-fik rounded-pill"><i class="bi bi-save me-1"></i> Simpan Maintenance</button></form></div></div><div class="col-lg-8"><div class="panel-card p-0 overflow-hidden"><div class="table-responsive"><table class="table table-hover mb-0"><thead><tr><th class="ps-3">Aset</th><th>Tanggal</th><th>Kondisi</th><th>Deskripsi</th><th class="text-end pe-3">Aksi</th></tr></thead><tbody><?php if(empty($maintenance)): ?><tr><td colspan="5" class="text-center text-muted py-5">Belum ada catatan maintenance.</td></tr><?php else: foreach($maintenance as $m): ?><tr><td class="ps-3"><div class="fw-semibold"><?= html_escape($m->nama_aset) ?></div><div class="small text-muted"><?= html_escape($m->kode_aset.' · '.$m->nama_ruangan) ?></div></td><td><?= html_escape($m->tanggal_maintenance) ?></td><td><span class="soft-badge"><?= html_escape($m->kondisi_setelah) ?></span></td><td><div class="small"><?= html_escape($m->deskripsi) ?></div></td><td class="text-end pe-3"><a class="btn btn-sm btn-outline-danger rounded-pill" href="<?= base_url('index.php/admin/maintenance/hapus/'.$m->id_maintenance) ?>" onclick="return confirm('Hapus catatan maintenance ini?')"><i class="bi bi-trash"></i></a></td></tr><?php endforeach; endif; ?></tbody></table></div></div></div></div></main><script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script></body></html>